   278|export async function generatePublicChatAnswer(input: {
   279|  message: string;
   280|  history: PublicChatHistoryItem[];
   281|  sessionId: string;
   282|  images?: PublicChatImageAttachment[];
   283|  documents?: DealDocumentAttachment[];
   284|  /** Raw attachment payload used to detect video attachments for video reading. */
   285|  rawAttachments?: unknown;
   286|}): Promise<PublicChatAnswerResult> {
   287|  const history = sanitizePublicChatHistory(input.history);
   288|  const images = (input.images ?? [])
   289|    .map((img) => ({ url: typeof img.url === 'string' ? img.url.trim() : '', mimeType: img.mimeType ?? null }))
   290|    .filter((img) => img.url.length > 0);
   291|  const documents = (input.documents ?? []).filter((doc) => typeof doc.url === 'string' && doc.url.trim().length > 0);
   292|  const videos = extractVideoAttachments(input.rawAttachments ?? { videos: [], attachments: [] });
   293|
   294|  // BLOCK 62 — Report Evidence Gate. `/public/chat` (the endpoint the in-app
   295|  // Chat tab AND the IVX Owner AI chat fall back to) had NO fake-deliverable
   296|  // gate, so report claims like "10,000 Buyers Report is ready" with placeholder
   297|  // links `[Buyers Report](#)` flowed through ungated. Gate every answer: a
   298|  // report-completion claim is allowed only when a real, download-verified
   299|  // deliverable exists for this conversation; otherwise the answer is rewritten
   300|  // to an honest REPORT NOT READY message. Never throws into the reply.
   301|  // REAL DB-COUNT TOOL — when the user asks for an investor/buyer/JV-deal count,
   302|  // execute an actual count=exact query against Supabase BEFORE generating the
   303|  // answer. The true numbers are injected into context so the model answers from
   304|  // real data, and `realQueryRan` is set so the query-narrative gate knows a real
   305|  // query actually executed this turn (otherwise such narration is fabricated).
   306|  let countReport: DbCountReport | null = null;
   307|  let countGroundingBlock: string | null = null;
   308|  const countTargets = detectCountIntent(input.message);
   309|  if (countTargets.length > 0) {
   310|    try {
   311|      countReport = await runDbCounts(countTargets);
   312|      countGroundingBlock = buildCountGroundingBlock(countReport);
   313|      console.log('[PublicChatAI] Real DB count tool ran:', {
   314|        sessionId: input.sessionId,
   315|        targets: countTargets,
   316|        anyExecuted: countReport.anyExecuted,
   317|        anyOk: countReport.anyOk,
   318|        results: countReport.results.map((r) => ({ target: r.target, ok: r.ok, count: r.count, reason: r.reason })),
   319|      });
   320|    } catch (countError) {
   321|      console.log('[PublicChatAI] DB count tool skipped:', countError instanceof Error ? countError.message : 'unknown');
   322|    }
   323|  }
   324|  const realQueryRan = countReport?.anyExecuted ?? false;
   325|
   326|  const gateAnswer = async (result: PublicChatAnswerResult): Promise<PublicChatAnswerResult> => {
   327|    let hasRealDeliverable = false;
   328|    try {
   329|      hasRealDeliverable = await conversationHasRealDeliverable(input.sessionId);
   330|    } catch (gateError) {
   331|      console.log('[PublicChatAI] Deliverable check skipped:', gateError instanceof Error ? gateError.message : 'unknown');
   332|    }
   333|
   334|    // QUERY-NARRATIVE GATE — block fabricated "I'm running these queries now"
   335|    // narration when no real query executed this turn.
   336|    const queryViolations = scanForUnbackedQueryNarrative(result.answer, realQueryRan);
   337|    if (queryViolations.length > 0) {
   338|      console.log('[PublicChatAI] Query-narrative gate blocked fabricated query narration:', {
   339|        sessionId: input.sessionId,
   340|        violations: queryViolations.map((v) => v.rule),
   341|        realQueryRan,
   342|      });
   343|      return { ...result, answer: buildNoLiveQueryMessage() };
   344|    }
   345|
