/** Helper to get GitHub SHA from Render info without duplicate API calls */
async function githubResultPlaceholder(renderInfo: Awaited<ReturnType<typeof fetchRenderInfo>>): Promise<{ sha: string | null; source: string; tokenStatus: string }> {
  const token = process.env.GITHUB_TOKEN?.trim();
  const repo = process.env.GITHUB_REPO_URL?.trim()
    ?.replace('https://github.com/', '')
    ?.replace('.git', '')
    || 'ibb142/rork-global-real-estate-invest';

  if (token) {
    try {
      const res = await fetch(`https://api.github.com/repos/${repo}/commits?per_page=1`, {
        headers: { Authorization: `Bearer ${token}`, Accept: 'application/vnd.github+json' },
        signal: AbortSignal.timeout(10000),
      });
      if (res.ok) {
        const data = await res.json() as Array<{ sha: string }>;
        if (data[0]?.sha) return { sha: data[0].sha, source: 'github_api', tokenStatus: 'VALID' };
      }
      if (res.status === 401) {
        return { sha: renderInfo.sha, source: 'render_deploy_commit (token_401_fallback)', tokenStatus: 'EXPIRED_OR_INVALID' };
      }
      return { sha: renderInfo.sha, source: `render_deploy_commit (github_http_${res.status})`, tokenStatus: `HTTP_${res.status}` };
    } catch {
      return { sha: renderInfo.sha, source: 'render_deploy_commit (github_fetch_failed)', tokenStatus: 'FETCH_FAILED' };
    }
  }
  return { sha: renderInfo.sha, source: 'render_deploy_commit', tokenStatus: 'NOT_SET' };
