     1|/**
     2| * IVX Deployment Chat Brain — Senior Deployment Executor
     3| *
     4| * Intercepts /deploy-* and /qa-* commands from the chat and returns
     5| * live production evidence. No placeholder responses. No fake verified.
     6| *
     7| * Commands:
     8| *   /deploy-status    — GitHub, Render, Production SHA comparison
     9| *   /deploy-now       — Trigger Render deploy via API
    10| *   /deploy-evidence  — Full deployment proof dump
    11| *   /deploy-verify    — Commit match check
    12| *   /deploy-rollback  — Rollback last Render deploy
    13| *   /qa-production    — Smoke test all production endpoints
    14| *   /qa-chat          — Test chat functionality
    15| *   /qa-members       — Test member system
    16| *   /qa-landing       — Test landing page
    17| *   /qa-engagement    — Test engagement features
    18| *   /commit-match     — Compare all SHAs
    19| */
    20|
    21|const DEPLOYMENT_BRAIN_VERSION = 'ivx-deployment-brain-v1-2026-07-01T22:15:00Z';
    22|
    23|// ── Types ────────────────────────────────────────────────────────────────────
    24|
    25|interface DeployStatusResult {
    26|  github: { sha: string | null; repo: string; branch: string; error: string | null };
    27|  render: { serviceId: string; deployId: string | null; sha: string | null; status: string | null; error: string | null };
    28|  production: { sha: string | null; bootTime: string | null; healthy: boolean; error: string | null };
    29|  commitMatch: boolean;
    30|  timestamp: string;
    31|}
