    34|  githubSha: string | null;
    35|  renderDeployId: string | null;
    36|  renderDeployedSha: string | null;
    37|  healthSha: string | null;
    38|  versionSha: string | null;
    39|  commitMatch: boolean;
    40|  productionStatus: string;
