    53|
    54|// ── Helpers ──────────────────────────────────────────────────────────────────
    55|
    56|function nowIso(): string {
    57|  return new Date().toISOString();
    58|}
    59|
    60|async function fetchJson(url: string): Promise<{ ok: boolean; status: number; body: unknown }> {
    61|  try {
    62|    const res = await fetch(url, { signal: AbortSignal.timeout(15000) });
    63|    const text = await res.text();
    64|    let body: unknown = text;
    65|    try { body = JSON.parse(text); } catch {}
    66|    return { ok: res.ok, status: res.status, body };
    67|  } catch (err) {
    68|    return { ok: false, status: 0, body: { error: err instanceof Error ? err.message : 'Network error' } };
    69|  }
    70|}
    71|
    72|function extractSha(data: unknown): string | null {
    73|  if (data && typeof data === 'object') {
    74|    const d = data as Record<string, unknown>;
    75|    return (typeof d.commit === 'string' ? d.commit : null) ??
    76|           (typeof d.commitShort === 'string' ? d.commitShort : null) ??
    77|           null;
    78|  }
    79|  return null;
    80|}
    81|
    82|// ── GitHub & Render Helpers ──────────────────────────────────────────────
    83|
    84|async function fetchGitHubSha(): Promise<string | null> {
    85|  const token = process.env.GITHUB_TOKEN?.trim();
    86|  if (!token) return null;
    87|
    88|  try {
    89|    const repo = process.env.GITHUB_REPO_URL?.trim()
    90|      ?.replace('https://github.com/', '')
    91|      ?.replace('.git', '')
    92|      || 'ibb142/rork-global-real-estate-invest';
    93|
    94|    const res = await fetch(`https://api.github.com/repos/${repo}/commits?per_page=1`, {
    95|      headers: { Authorization: `Bearer ${token}` },
    96|      signal: AbortSignal.timeout(10000),
    97|    });
    98|    if (!res.ok) return null;
    99|    const data = await res.json() as Array<{ sha: string }>;
   100|    return data[0]?.sha ?? null;
   101|  } catch {
   102|    return null;
   103|  }
   104|}
