   106|async function fetchRenderInfo(): Promise<{
   107|  serviceId: string | null;
   108|  deployId: string | null;
   109|  sha: string | null;
   110|  status: string | null;
   111|  repo: string | null;
   112|  error: string | null;
   113|}> {
   114|  const apiKey = process.env.RENDER_API_KEY?.trim();
   115|  const serviceId = process.env.RENDER_SERVICE_ID?.trim() || 'srv-d7t9ivreo5us73ftose0';
   116|
   117|  if (!apiKey) {
   118|    return { serviceId, deployId: null, sha: null, status: 'autoDeployTrigger: commit active', repo: null, error: null };
   119|  }
   120|
   121|  try {
   122|    const [svcRes, deployRes] = await Promise.all([
   123|      fetch(`https://api.render.com/v1/services/${serviceId}`, {
   124|        headers: { Authorization: `Bearer ${apiKey}` },
   125|        signal: AbortSignal.timeout(10000),
   126|      }),
   127|      fetch(`https://api.render.com/v1/services/${serviceId}/deploys?limit=1`, {
   128|        headers: { Authorization: `Bearer ${apiKey}` },
   129|        signal: AbortSignal.timeout(10000),
