   131|    ]);
   132|
   133|    const svcData = svcRes.ok ? await svcRes.json() as Record<string, unknown> : null;
   134|    const deployData = deployRes.ok ? await deployRes.json() as Array<Record<string, unknown>> : null;
   135|    const latestDeploy = deployData?.[0]?.deploy as Record<string, unknown> | undefined;
   136|
   137|    return {
   138|      serviceId,
