   141|      status: (latestDeploy?.status as string) ?? 'unknown',
   142|      repo: (svcData?.repo as string) ?? null,
   143|      error: null,
   144|    };
   145|  } catch (err) {
   146|    return { serviceId, deployId: null, sha: null, status: null, repo: null, error: err instanceof Error ? err.message : 'Render API unreachable' };
   147|  }
   148|}
   149|
   150|async function fetchSupabaseTableCounts(): Promise<string> {
   151|  const url = process.env.SUPABASE_URL?.trim();
   152|  const key = process.env.SUPABASE_SERVICE_ROLE_KEY?.trim();
   153|  if (!url || !key) return 'SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY not configured in this environment.';
   154|
   155|  const tables = ['properties', 'members', 'investors', 'wallets', 'public_chat_messages', 'ai_usage_logs', 'ivx_agent_jobs'];
   156|  const results: string[] = [];
   157|
   158|  for (const table of tables) {
   159|    try {
   160|      const res = await fetch(`${url}/rest/v1/${table}?select=count`, {
   161|        headers: { apikey: key, Authorization: `Bearer ${key}`, Prefer: 'count=exact' },
   162|        signal: AbortSignal.timeout(8000),
   163|      });
   164|      const data = await res.json() as unknown[];
   165|      results.push(`${table}: ${Array.isArray(data) ? data.length : '?'} rows`);
   166|    } catch {
   167|      results.push(`${table}: ERROR`);
   168|    }
   169|  }
   170|  return results.join('\n');
   171|}
