   175|export async function handleDeployStatus(): Promise<string> {
   176|  const [healthRes, versionRes, githubSha, renderInfo] = await Promise.all([
   177|    fetchJson('https://api.ivxholding.com/health'),
   178|    fetchJson('https://api.ivxholding.com/version'),
   179|    fetchGitHubSha(),
   180|    fetchRenderInfo(),
   181|  ]);
   182|
   183|  const healthSha = extractSha(healthRes.body);
   184|  const versionSha = extractSha(versionRes.body);
   185|  const healthy = healthRes.status === 200;
   186|  const bootTime = healthRes.body && typeof healthRes.body === 'object'
   187|    ? (healthRes.body as Record<string, unknown>).bootTime ?? null
   188|    : null;
   189|
   190|  const commitMatch = healthSha !== null && healthSha === versionSha && healthSha === githubSha;
   191|
   192|  const result: DeployStatusResult = {
   193|    github: {
   194|      sha: githubSha,
   195|      repo: renderInfo.repo || 'ibb142/rork-global-real-estate-invest',
   196|      branch: 'main',
   197|      error: githubSha ? null : 'GITHUB_TOKEN not available — cannot verify GitHub SHA',
   198|    },
